svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('#data-layer');
    var dotsLayer   = svgEl.querySelector('#dots-layer');
    var hitLayer    = svgEl.querySelector('#hit-layer');
    var tipLayer    = svgEl.querySelector('#tip-layer');
    var defs        = svgEl.querySelector('defs');
    var plot        = { x:68, y:100, width:772, height:400 };
    var revealDelays = [0, 0.25, 0.50, 0.75, 1.00];
    var plotL = 42, plotR = 840, plotT = 100;

    var series = [
      { id:1, cls:'series-1', label:'Cyan',    vals:[100,119,130,146,151,175,185,210], ys:[322.2,288.4,268.9,240.4,231.6,188.9,171.1,126.7] },
      { id:2, cls:'series-2', label:'Emerald', vals:[68,81,89,98,99,114,117,138],      ys:[379.1,356.0,341.8,325.8,324.0,297.3,292.0,254.7] },
      { id:3, cls:'series-3', label:'Amber',   vals:[40,50,54,58,55,65,62,76],         ys:[428.9,411.1,404.0,396.9,402.2,384.4,389.8,364.9] },
      { id:4, cls:'series-4', label:'Rose',    vals:[22,28,29,29,30,37,31,41],         ys:[460.9,450.2,448.4,448.4,446.7,434.2,444.9,427.1] },
      { id:5, cls:'series-5', label:'Violet',  vals:[10,13,11,15,13,17,15,19],         ys:[482.2,476.9,480.4,473.3,476.9,469.8,473.3,466.2] }
    ];
    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs = [68,171,274,377,480,583,686,789];
    var totals = xs.map(function(_, qi) {
      return series.reduce(function(sum, s) { return sum + s.vals[qi]; }, 0);
    });
    var allTips = {};

    var el = ctx.el;

    [
      { selector:'#band-1-2', id:1 },
      { selector:'#band-2-3', id:2 },
      { selector:'#band-3-4', id:3 },
      { selector:'#band-4-5', id:4 },
      { selector:'#band-base', id:5 }
    ].forEach(function(band, i) {
      var area = svgEl.querySelector(band.selector);
      if (!area) return;
      var areaClip = el('clipPath', { id:'line-stack-reveal-' + band.id, clipPathUnits:'userSpaceOnUse' });
      var revealRect = el('rect', { x:plot.x, y:plot.y, width:0, height:plot.height });
      areaClip.appendChild(revealRect);
      defs.appendChild(areaClip);
      area.setAttribute('clip-path', 'url(#line-stack-reveal-' + band.id + ')');
      (function(rect, delay) {
        var startAt = performance.now() + delay * 1000;
        var duration = 1200;
        function ease(t) { return 1 - Math.pow(1 - t, 3); }
        function tick(now) {
          if (now < startAt) return requestAnimationFrame(tick);
          var p = Math.min((now - startAt) / duration, 1);
          rect.setAttribute('width', String(plot.width * ease(p)));
          if (p < 1) requestAnimationFrame(tick);
        }
        requestAnimationFrame(tick);
      }(revealRect, revealDelays[i]));
    });

    series.forEach(function(s) {
      xs.forEach(function(x, qi) {
        var y = s.ys[qi];
        var key = s.id + '_' + qi;
        var delay = ((s.id - 1) * 0.25 + qi * 0.06) + 's';

        var dg = el('g', {'class':'dot-g', id:'d'+key});
        var inner = el('g', {'class':'dot-inner', style:'transform-origin:'+x+'px '+y+'px'});
        inner.style.animation = 'popDot 0.35s cubic-bezier(0.34,1.4,0.64,1) ' + delay;
        inner.addEventListener('animationend', function() {
          inner.style.animation = 'none';
          inner.classList.add('visible');
        }, { once:true });
        inner.appendChild(el('circle', { cx:x, cy:y, r:5, 'class':s.cls, stroke:'none' }));
        dg.appendChild(inner);
        dotsLayer.appendChild(dg);

        dotsLayer.appendChild(el('circle', { cx:x, cy:y, r:4, 'class':'col-dot ' + s.cls, 'data-col':qi, stroke:'none' }));
      });
    });

    function setColumnHover(qi, mouseY) {
      dataLayerEl.classList.add('hovering');
      svgEl.querySelectorAll('.line-path').forEach(function(line) { line.classList.remove('active'); });
      svgEl.querySelectorAll('.area-path').forEach(function(area) { area.classList.remove('active'); });
      svgEl.querySelectorAll('.dot-inner').forEach(function(dot) { dot.classList.remove('active'); });
      var bestSid = series[0].id, bestDist = Infinity;
      if (typeof mouseY === 'number') {
        series.forEach(function(s) {
          var dist = Math.abs(s.ys[qi] - mouseY);
          if (dist < bestDist) { bestDist = dist; bestSid = s.id; }
        });
      }
      var activeLine = svgEl.querySelector('#line-'+bestSid);
      if (activeLine) activeLine.classList.add('active');
      var activeArea = svgEl.querySelector('.area-path[data-series="'+bestSid+'"]');
      if (activeArea) activeArea.classList.add('active');
      series.forEach(function(s) {
        var inner = svgEl.querySelector('#d'+s.id+'_'+qi+' .dot-inner');
        if (inner) inner.classList.toggle('active', s.id === bestSid);
      });
      dotsLayer.querySelectorAll('.col-dot').forEach(function(dot) { dot.classList.remove('active'); });
      dotsLayer.querySelectorAll('.col-dot[data-col="'+qi+'"]').forEach(function(dot) {
        dot.classList.toggle('active', dot.getAttribute('class').indexOf('series-'+bestSid) !== -1);
      });
    }

    function clearColumnHover() {
      dataLayerEl.classList.remove('hovering');
      svgEl.querySelectorAll('.line-path').forEach(function(line) { line.classList.remove('active'); });
      svgEl.querySelectorAll('.area-path').forEach(function(area) { area.classList.remove('active'); });
      svgEl.querySelectorAll('.dot-inner').forEach(function(dot) { dot.classList.remove('active'); });
      dotsLayer.querySelectorAll('.col-dot').forEach(function(dot) { dot.classList.remove('active'); });
    }

    xs.forEach(function(x, qi) {
      var tipG = ctx.buildStackedSideTooltip(tipLayer, {
        id: 'tip_' + qi,
        header: quarters[qi],
        rows: series.map(function(s) {
          return { cls: s.cls, label: s.label, value: '$' + s.vals[qi] + 'M' };
        }),
        totalLabel: 'Total',
        totalValue: '$' + totals[qi] + 'M',
        anchorX: x,
        anchorY: 300,
        plotL: plotL,
        plotR: plotR,
        plotT: plotT,
        plotB: 500
      });
      allTips[qi] = tipG;

      var hx1 = Math.max(68, x - 56);
      var hx2 = Math.min(832, x + 56);
      var hit = el('rect', {x:hx1, y:100, width:hx2-hx1, height:400, fill:'transparent', cursor:'crosshair'});
      hitLayer.appendChild(hit);
      var ch = svgEl.querySelector('#ch'+qi);

      hit.addEventListener('mouseenter', function(e) {
        var sp = ctx.eventToSvgPoint(svgEl, e);
        setColumnHover(qi, sp.y);
        ctx.setOpacity(allTips[qi], 1);
        ctx.setOpacity(ch, 1);
      });
      hit.addEventListener('mousemove', function(e) {
        var sp = ctx.eventToSvgPoint(svgEl, e);
        setColumnHover(qi, sp.y);
      });
      hit.addEventListener('mouseleave', function() {
        clearColumnHover();
        ctx.setOpacity(allTips[qi], null);
        ctx.setOpacity(ch, null);
      });
    });

    var lastDelay = (series.length - 1) * 0.25 + (xs.length - 1) * 0.06;
    setTimeout(function(){ dataLayerEl.classList.add('ready'); }, (lastDelay + 0.35) * 1000 + 100);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
